queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasCinematographies ?parent . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cinematographies } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?technique_name WHERE {
  ?cinematographies_techniques a :Cinematographies_Techniques .
  ?techniques a :Techniques .
  ?cinematographies_techniques p:hasTechniques ?techniques .
  ?cinematographies a :Cinematographies .
  ?cinematographies_techniques p:hasCinematographies ?cinematographies .
  ?cinematographies p:name ?name .
  ?techniques p:technique_name ?technique_name .
} }
  collective: { SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasCinematographies ?parent . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cinematographies } }
  FILTER(?nf = ?total)
} }
}
